('tokyo', 'Tokyo', (SELECT id FROM countries WHERE name='Japan'), 'Modern city with tradition, technology and great food.', '/images/tokyo.png', 'March–April', 'Cherry Blossom Season', 'Thank you = Arigato'),
('paris', 'Paris', (SELECT id FROM countries WHERE name='France'), 'Museums, cafés and iconic landmarks.', '/images/paris.png', 'May–Sept', 'Bastille Day (July 14)', 'Please = S''il vous plaît'),
('rome', 'Rome', (SELECT id FROM countries WHERE name='Italy'), 'Ancient history, architecture and culture.', '/images/rome.png', 'Sept–Oct', 'Easter Celebrations', 'Excuse me = Mi scusi'),
('barcelona', 'Barcelona', (SELECT id FROM countries WHERE name='Spain'), 'Beaches, art and architecture.', '/images/barcelona.png', 'May–June', 'Primavera Sound Festival', 'The bill = La cuenta'),
('newyork', 'New York', (SELECT id FROM countries WHERE name='USA'), 'City life, entertainment and famous sights.', '/images/newyork.png', 'Sept–Nov', 'New Year''s Eve Ball Drop', 'Tip 20% at restaurants'),
('marrakech', 'Marrakech', (SELECT id FROM countries WHERE name='Morocco'), 'Markets, culture, and local experiences.', '/images/marrakech.png', 'March–May', 'International Film Festival', 'Thank you = Shokran'),
('bangkok', 'Bangkok', (SELECT id FROM countries WHERE name='Thailand'), 'Street food, temples and nightlife.', '/images/bangkok.png', 'Nov–Feb', 'Songkran (Water Festival)', 'Hello = Sawasdee'),
('reykjavik', 'Reykjavik', (SELECT id FROM countries WHERE name='Iceland'), 'Nature, northern lights and unique landscapes.', '/images/reykjavik.png', 'Sept–March', 'Iceland Airwaves', 'Cheers = Skál!'),
('siemreap', 'Siem Reap', (SELECT id FROM countries WHERE name='Cambodia'), 'Gateway to the ancient ruins of Angkor Wat.', '/images/siemreap.png', 'Dec–Feb', 'Khmer New Year (April)', 'Hello = Susadei');
